cases.query:
#graphql
mutation InvalidMarketLocalization($resourceId: ID!, $marketLocalizations: [MarketLocalizationRegisterInput!]!) {
  marketLocalizationsRegister(resourceId: $resourceId, marketLocalizations: $marketLocalizations) {
    marketLocalizations { key value updatedAt outdated market { id name } }
    userErrors { field message code }
  }
}

#graphql
mutation InvalidMarketLocalizationRemove($resourceId: ID!, $marketLocalizationKeys: [String!]!, $marketIds: [ID!]!) {
  marketLocalizationsRemove(resourceId: $resourceId, marketLocalizationKeys: $marketLocalizationKeys, marketIds: $marketIds) {
    marketLocalizations { key value updatedAt outdated market { id name } }
    userErrors { field message code }
  }
}
